def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[0]
    original_prs = Presentation(original_ppt_path)
    original_slide = original_prs.slides[0]

    def get_textboxes(slide):
        return [shape for shape in slide.shapes if shape.has_text_frame and shape.text_frame and shape.text.strip()]
    orig_texts = set(shape.text.strip() for shape in get_textboxes(original_slide))
    mod_textboxes = get_textboxes(slide)

    # Find the text box with exact required text that is new
    for shape in mod_textboxes:
        if shape.text.strip() == 'Updated Presentation' and shape.text.strip() not in orig_texts:
            # Check its position
            slide_width = prs.slide_width
            slide_height = prs.slide_height
            # Top-right: let's say within top 20% of Y and rightmost 20% of X
            x, y = shape.left, shape.top
            w, h = shape.width, shape.height
            # Position is measured from top-left of shape
            # Check y is in top 20%
            in_top = (y + h/2) < (slide_height * 0.2)
            # Check right edge is in rightmost 20%
            right_edge = x + w
            in_right = right_edge > (slide_width * 0.8)
            if in_top and in_right:
                return ("Text box is in top-right corner.", 1.0)
            elif in_top:
                return ("Text box in top but not far right.", 0.5)
            elif in_right:
                return ("Text box in right but not top.", 0.5)
            else:
                return ("Text box is not in top-right corner.", 0.0)
    return ("Required text box not found for position check.", 0.0)

def compute_score() -> tuple[str, float]:
    # Check if anything except the required text box was changed on slide 1
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[0]
    original_prs = Presentation(original_ppt_path)
    original_slide = original_prs.slides[0]
    def get_textboxes(slide):
        return [shape for shape in slide.shapes if shape.has_text_frame and shape.text_frame and shape.text.strip()]
    orig_texts = set(shape.text.strip() for shape in get_textboxes(original_slide))
    mod_textboxes = get_textboxes(slide)
    mod_texts = set(shape.text.strip() for shape in mod_textboxes)
    added_texts = mod_texts - orig_texts
    # Remove the required box from diff
    extraneous = [t for t in added_texts if t != 'Updated Presentation']
    # Now check for removed or modified shapes
    orig_shapes = {(shape.left, shape.top, shape.width, shape.height, shape.text.strip()) for shape in get_textboxes(original_slide)}
    mod_shapes = {(shape.left, shape.top, shape.width, shape.height, shape.text.strip()) for shape in get_textboxes(slide)}
    removed = orig_shapes - mod_shapes
    modified = [s for s in orig_shapes if s not in mod_shapes]
    if extraneous or removed or modified:
        return (f"Extraneous changes detected on slide 1 (added: {extraneous}, removed/modified: {len(removed)+len(modified)} shapes)", 0.0)
    return ("No extraneous changes detected on slide 1.", 1.0)
